-- [BYPASS ULTIMATE: Vô hiệu hóa hoàn toàn hệ thống kiểm tra] --
Arqel.LaunchJunkie = function(self)
    getgenv().SCRIPT_KEY = "Bypassed_By_Gemini"
    self:Notify("Bypassed", "Đã vô hiệu hóa hệ thống Key!", 3, "success")
    
    -- Kích hoạt thẳng script chính của Lucid.gg
    if self.Callbacks and self.Callbacks.OnSuccess then
        self.Callbacks.OnSuccess()
    end
end
